function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // dp_up[i]: Maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is greater than the preceding element (i.e., ... < nums[i] or ... > nums[i] < nums[i])
    // In the context of alternation:
    // If the previous transition was 'up' (a < b), the current element must start a 'down' transition (b > c).
    // If the previous transition was 'down' (a > b), the current element must start an 'up' transition (b < c).
    //
    // Let's redefine based on the relation *to the previous element in the subsequence*:
    // dp_up[i]: Max score ending at i, where nums[i] is greater than the preceding element in the subsequence (i.e., ... < nums[i]).
    // dp_down[i]: Max score ending at i, where nums[i] is smaller than the preceding element in the subsequence (i.e., ... > nums[i]).

    // Initialize DP arrays. A single element subsequence has a score equal to its value.
    const dp_up = new Array(n).fill(0);
    const dp_down = new Array(n).fill(0);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: A subsequence of length 1 always exists, score is nums[i]
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        for (let j = 0; j < i; j++) {
            // Check the distance constraint
            if (i - j >= k) {
                // Case 1: nums[i] > nums[j] (Current transition is 'up')
                // This transition must follow a 'down' transition ending at j (i.e., nums[j] > prev_element)
                // The score would be dp_down[j] + nums[i]
                if (nums[i] > nums[j]) {
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
                }

                // Case 2: nums[i] < nums[j] (Current transition is 'down')
                // This transition must follow an 'up' transition ending at j (i.e., nums[j] < prev_element)
                // The score would be dp_up[j] + nums[i]
                if (nums[i] < nums[j]) {
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
                }

                // Note: If nums[i] == nums[j], no valid alternating sequence can be extended.
            }
        }

        // Update the overall maximum score found so far
        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}

